#!/usr/bin/env python3
"""追加第二批翻译数据"""
import json

with open('/workspace/news-hub/scripts/translations.json','r',encoding='utf-8') as f:
    T = json.load(f)

def a(k,t,s):
    T[k] = {"title":t,"summary":s}

a("'Japanification' Doesn't Fit","「日本化」不适用：中国经济停滞需要自己的命名","彭博社评论指出，用「日本化」描述中国经济停滞并不准确，中国面临的结构性挑战有其独特性。文章分析了中国经济放缓与日本90年代泡沫破裂的本质区别：中国仍处于城镇化进程中，人均GDP远低于日本当年水平，政府调控手段更为直接有效。中国的债务结构、人口老龄化和房地产困境与日本有相似之处，但中国的国有经济体系和金融管制使得危机传导机制不同。文章认为，中国经济面临的是一个混合了结构性转型、债务重组和地缘政治压力的复合型挑战，需要新的分析框架来理解，简单套用日本模式会产生误导性结论。")

a("Judge Scrutinizes Decision","法官审视放弃对印度亿万富翁指控的决定","纽约时报报道，一名联邦法官正审视美国司法部撤回对一名印度亿万富翁刑事指控的决定。此案涉及跨国商业犯罪，司法部突然撤诉引发司法独立性质疑。法官在听证会上表示，检方需提供充分理由证明撤诉决定不受外部政治影响。该亿万富翁所在的印度企业集团在美有大量商业利益，此案受到美印两国政府关注。分析人士指出，此案可能成为检验美国司法独立性的重要案例，也反映了跨国商业利益与司法公正之间的张力。法官的审查结果将对未来类似案件产生先例效应。")

a("Tracking Trump: Government to restrict","追踪特朗普：政府限制新ChatGPT模型，前特朗普助手认罪","华盛顿邮报综合报道，美国政府决定限制新版ChatGPT模型的使用范围，同时前特朗普助手在相关案件中认罪。报道涵盖多条政治与科技交叉的重要新闻：OpenAI新模型面临政府安全审查，前特朗普政府官员认罪涉及机密信息处理不当，副总统万斯在公开场合为尼克松辩护。这些事件共同反映了美国政治与科技监管日益交织的趋势。政府对AI模型的管控正在从建议层面上升到强制执行层面，可能对美国AI产业的创新速度产生深远影响。")

a("Opinion | Feds controlling","观点：联邦政府控制ChatGPT访问误判了AI威胁","华盛顿邮报评论文章认为，联邦政府试图控制ChatGPT访问权限的做法误读了AI的真正威胁。文章指出，过度关注模型访问限制可能忽视了AI在实际部署中面临的更深层次问题，如偏见、误信息和自动化决策的问责机制。作者认为，当前的管控思路过于聚焦国家安全视角，忽视了公民权利和市场竞争维度。文章呼吁建立更平衡的AI治理框架，在保障安全的同时不扼杀创新。这一观点反映了美国国内关于AI监管路径的激烈辩论，科技界与安全界的分歧正在加深。")

a("Trump threatens 100% tariff","特朗普以100%关税威胁欧洲国家，因数字服务税争端","BBC报道，特朗普威胁对征收数字服务税的欧洲国家加征100%关税，加剧了美欧贸易紧张局势。此举针对法国、英国等已实施数字服务税的国家，特朗普政府认为这些税收歧视美国科技企业。欧盟方面表示将采取反制措施，跨大西洋贸易战风险上升。分析人士指出，数字服务税争端反映了美欧在数字经济治理上的根本分歧，也可能影响正在进行的全球数字税谈判。若关税威胁兑现，将对欧洲奢侈品、汽车和农产品出口造成严重打击，同时推高美国消费者价格。")

a("OpenAI and Anthropic limit","OpenAI和Anthropic在网络安全审查期间限制新AI模型访问","美联社报道，OpenAI和Anthropic在政府网络安全审查期间，将新AI模型仅向特朗普政府批准的客户开放。这标志着美国对前沿AI模型实施更严格管控，政府正建立AI模型安全审查机制，要求模型发布前需通过国家安全评估。OpenAI的GPT-5.6和Anthropic的Mythos 5均在审查范围内。此举引发科技界对创新自由的担忧，部分行业人士认为过度管控可能削弱美国在AI领域的全球竞争力。同时，这也为其他国家AI监管提供了参考框架，可能影响全球AI治理走向。")

a("Venezuela's Earthquakes Test","委内瑞拉地震考验特朗普对德尔西·罗德里格斯的政治押注","华尔街日报报道，委内瑞拉近期地震灾害考验了特朗普政府与委内瑞拉反对派人物德尔西·罗德里格斯的政治合作。美国此前押注罗德里格斯作为推动委内瑞拉政治过渡的关键人物，但地震救援暴露了反对派在危机管理中的局限性。马杜罗政府借地震开展救援行动，争取了部分民意支持。分析人士指出，自然灾害正在重塑委内瑞拉政治格局，美国的策略可能需要调整。委内瑞拉的人道主义危机和政治僵局相互交织，地震救灾成为各方政治博弈的新战场。")

a("Mexico Names New CFO","墨西哥为困境中的石油巨头Pemex任命新CFO","彭博社报道，墨西哥政府为深陷财务困境的国家石油公司Pemex任命新任首席财务官。Pemex背负超过1000亿美元债务，是全球负债最多的石油公司之一。新CFO面临艰巨的财务重组任务，需要在维持产量和偿还债务之间取得平衡。墨西哥政府此前已通过注资和税收减免等方式援助Pemex，但成效有限。分析人士指出，Pemex的财务困境是墨西哥经济的结构性问题，新CFO的任命可能预示着更深层次的改革即将推出。国际信用评级机构正密切关注Pemex的财务状况。")

a("US allows Anthropic to release","美国允许Anthropic向「受信任」机构发布Mythos AI模型","路透社报道，美国政府已批准Anthropic向「受信任」的美国机构发布Mythos AI模型。这是在网络安全审查后，美国对前沿AI模型管控的最新动态。审查机制要求AI公司在发布新模型前需通过国家安全评估，政府可限制特定模型的部署范围。Anthropic的Mythos模型在通过审查后被允许向经审批的机构开放，标志着美国AI安全治理框架进入实质运作阶段。分析人士指出，这一模式可能成为前沿AI模型发布的标准流程，影响整个行业的研发和商业化节奏。")

a("OpenAI defers public rollout","OpenAI推迟GPT-5.6公开发布，美国政府寻求前沿AI早期访问权","路透社报道，OpenAI推迟了GPT-5.6模型的公开发布，原因是美国政府寻求在前沿AI模型上线前获得早期访问权限。这反映了政府对AI安全的日益关注，也标志着前沿AI模型监管进入新阶段。美国政府正在建立AI模型预审查制度，要求企业在发布重大模型前通知政府并进行安全评估。此举可能改变AI行业的发布节奏，企业需要在创新速度与合规要求之间寻找平衡。分析人士指出，这实际上赋予了政府对前沿AI发展的否决权，可能影响美国在全球AI竞赛中的速度优势。")

a("New Mexico opens criminal","新墨西哥州对DEA展开刑事调查，探员被指放任芬太尼流入街头","美联社报道，新墨西哥州对缉毒局（DEA）展开刑事调查，指控DEA探员允许芬太尼流入街头。调查聚焦于DEA在阿尔伯克基市的一次行动，探员 allegedly 监视而非阻止一批芬太尼交易，导致毒品流入社区。这是执法机构内部监管的重大案件，引发对DEA执法伦理的质疑。新墨西哥州总检察长表示，调查旨在确定DEA的做法是否违反州法。DEA方面否认不当行为，称其行动遵循标准程序。此案可能影响联邦与州级执法机构的合作关系，也凸显了芬太尼危机的复杂性。")

a("Inside a Debate at OpenAI","揭秘OpenAI内部关于大规模枪击案信息的争论","华尔街日报披露，OpenAI内部就AI模型如何处理大规模枪击事件信息展开了激烈争论。一方认为模型应限制与枪击案相关的敏感内容生成，防止被用于恶意目的；另一方则认为过度限制会损害信息自由和新闻功能。这场争论反映了AI安全与信息自由之间的深层矛盾，也暴露了AI公司在内容审核上面临的道德困境。OpenAI最终采取了折中方案，但内部分歧仍未完全消解。分析人士指出，此类争论将随着AI能力增强而更加频繁，行业需要建立更清晰的内容治理准则。")

a("Apple's Vision Pro and Smart","苹果Vision Pro和智能眼镜负责人Paul Meade跳槽至OpenAI","彭博社报道，苹果Vision Pro和智能眼镜项目负责人Paul Meade即将离职加入OpenAI。这凸显了AI公司与硬件厂商之间的人才争夺战正愈演愈烈。Meade在苹果负责混合现实和可穿戴设备的硬件开发，其离职对苹果的智能眼镜项目可能造成影响。OpenAI正在组建硬件团队，探索AI专用设备的开发，Meade的加入将为这一 effort 注入关键硬件 expertise。分析人士指出，AI人才战正从软件领域扩展到硬件领域，科技巨头之间的人才流动将重塑行业竞争格局。")

a("Bloomberg Intelligence: AI Cost","彭博情报：AI成本考验科技股，苹果上调价格加剧担忧","彭博情报分析指出，AI开发成本正在考验科技股估值，苹果上调产品价格进一步加剧市场担忧。投资者开始重新评估AI投资回报周期，科技股面临估值调整压力。苹果、微软等公司投入巨额AI研发费用，但短期商业化前景不明朗。与此同时，AI芯片成本上涨推高了硬件产品价格，可能抑制消费需求。分析认为，AI行业正进入投入高峰期，短期内盈利压力加大，市场可能经历一轮估值修正。长期来看，AI的价值创造潜力仍然巨大，但投资者需要更耐心的资本布局。")

a("Thailand's Saha teams","泰国Saha与日本软银合作开发AI驱动服务","日经亚洲报道，泰国零售集团Saha与日本软银合作开发AI驱动服务。这体现了东南亚企业与日本科技公司在AI领域的跨国合作趋势。Saha在泰国拥有广泛的零售网络和消费品牌组合，软银则提供AI技术和平台支持。双方计划在零售智能化、客户数据分析和供应链优化等领域展开合作。分析人士指出，东南亚正成为AI应用的重要市场，日本科技企业正通过合作方式加速进入该区域，与中国和美国科技公司竞争。这一合作模式可能成为日本企业拓展东南亚AI市场的典型路径。")

a("Apple is raising prices","苹果正在涨价，iPhone会跟进吗？","华盛顿邮报分析苹果产品涨价趋势，探讨iPhone是否将成为下一个涨价的旗舰产品。关税压力和AI芯片成本上升是主要推手。苹果已上调iPad和Mac产品线价格，部分型号涨幅超过10%。分析人士指出，iPhone作为苹果最大收入来源，其定价策略更为敏感，涨价可能影响销量。但AI功能升级和芯片成本上涨可能迫使苹果在下一代iPhone中提价。消费者对科技产品涨价的接受度正在下降，苹果需要在维持利润率和保护市场份额之间取得平衡。关税政策的不确定性增加了定价决策的难度。")

a("Morgan Stanley, Goldman","摩根士丹利和高盛股价下跌，因OpenAI IPO可能推迟","彭博社报道，摩根士丹利和高盛股价因OpenAI IPO可能推迟而下跌。OpenAI上市时间表的不确定性影响了华尔街对AI投资链条的预期。两家投行此前被预期将担任OpenAI IPO的主承销商，推迟上市意味着巨额承销收入的延迟。分析人士指出，OpenAI的IPO时间取决于其商业模式成熟度和监管环境变化，当前AI模型管控趋严可能是推迟因素之一。华尔街对AI相关IPO的期待值很高，OpenAI的上市节奏将影响整个AI板块的估值情绪。")

a("India opens steel dumping","印度对中国、日本、俄罗斯发起钢铁反倾销调查","路透社报道，印度已对来自中国、日本和俄罗斯的钢铁产品发起反倾销调查。这反映了印度保护本土钢铁产业的贸易政策取向。印度钢铁部此前收到国内企业投诉，称进口钢铁以低于成本价销售，损害了本土产业。调查可能导致印度对相关产品征收反倾销税。分析人士指出，印度正加快推进制造业本土化，钢铁是关键基础材料，保护本土产能符合「印度制造」战略。此举可能引发中国和日本的贸易反弹，增加亚太贸易摩擦风险。")

a("Magnitude 6.6 earthquake","菲律宾南部发生6.6级地震，未发布海啸预警","路透社报道，菲律宾南部发生6.6级地震，目前未发布海啸预警。地震发生在环太平洋火山地震带，相关损失评估正在进行中。菲律宾地震频繁，此次震级较高但震中位于海域，降低了陆地破坏程度。当地政府已启动应急响应机制，检查基础设施受损情况。目前暂无重大人员伤亡报告，但部分建筑出现裂缝。菲律宾位于太平洋火圈上，每年经历数百次有感地震，政府已建立较为完善的地震应急体系。此次地震再次提醒该地区自然灾害风险的持续性。")

a("Brazil posts narrower","巴西5月经常账户赤字小于预期","路透社报道，巴西5月经常账户赤字低于市场预期，显示其外部经济平衡有所改善。这一数据缓解了市场对巴西国际收支的担忧。贸易顺差和外国直接投资流入是改善的主要原因。巴西央行数据显示，5月贸易盈余抵消了部分服务贸易逆差，外资流入保持稳定。分析人士指出，巴西经济基本面正在改善，但仍受财政赤字和政治不确定性制约。雷亚尔汇率近期波动较大，经常账户数据的改善为汇率提供了一定支撑。未来几个月的贸易表现将是观察巴西经济走势的重要指标。")

a("Apple, Micron, OpenAI and A.I.","苹果、美光、OpenAI与AI的艰难之夏","纽约时报综合分析苹果、美光、OpenAI等科技巨头在AI浪潮中面临的挑战。从成本上升到监管压力，AI产业正经历一个充满波动的夏天。苹果面临AI功能整合困难和产品涨价压力，美光等芯片制造商在AI需求与消费电子需求之间艰难平衡，OpenAI则面临政府监管和商业化压力。文章指出，AI产业的「粗放增长期」正在结束，企业需要证明AI投资的商业回报。投资者情绪从乐观转向谨慎，科技股估值面临重新校准。尽管长期前景仍然看好，但短期内AI产业将经历一段痛苦的调整期。")

with open('/workspace/news-hub/scripts/translations.json','w',encoding='utf-8') as f:
    json.dump(T,f,ensure_ascii=False,indent=2)
print(f"总计 {len(T)} 条翻译")
